blocks.body:
{
    "level": "A2–B1",
    "intro": "W tym temacie nauczysz się <strong>odróżniać przymiotniki od przysłówków</strong>, poprawnie je tworzyć i używać w zdaniach.",
    "rules": [
        {
            "label": "Adjectives",
            "color": "emerald",
            "text": "<strong>Przymiotniki</strong> opisują rzeczowniki:",
            "example": "a quick answer, She is happy."
        },
        {
            "label": "Adverbs",
            "color": "blue",
            "text": "<strong>Przysłówki</strong> opisują czasowniki:",
            "example": "He answered quickly. She smiled happily."
        },
        {
            "label": "Formation",
            "color": "amber",
            "text": "Większość przysłówków = <em>adjective + -ly</em>:",
            "example": "slow → slowly, careful → carefully"
        }
    ]
}

{
    "title": "1. Podstawowa różnica",
    "intro": "Przymiotniki i przysłówki odpowiadają na różne pytania i opisują różne części mowy:",
    "rows": [
        {
            "en": "Adjectives",
            "ua": "Przymiotniki",
            "note": "Opisują rzeczowniki (jaki? jaka? jakie?)"
        },
        {
            "en": "Adverbs",
            "ua": "Przysłówki",
            "note": "Opisują czasowniki (jak? kiedy? gdzie?)"
        },
        {
            "en": "a beautiful dress",
            "ua": "piękna sukienka",
            "note": "przymiotnik → opisuje dress"
        },
        {
            "en": "She dances beautifully.",
            "ua": "Ona tańczy pięknie."
            ,"note": "przysłówek → opisuje dances"
        }
    ],
    "warning": "💡 Zadaj sobie pytanie: co jest opisywane? Jeśli rzeczownik — użyj przymiotnika. Jeśli czasownik — użyj przysłówka."
}

{
    "title": "2. Tworzenie przysłówków",
    "sections": [
        {
            "label": "Ogólna zasada: + -ly",
            "color": "emerald",
            "description": "Większość przysłówków tworzymy przez dodanie <strong>-ly</strong> do przymiotnika:",
            "examples": [
                {
                    "en": "quick → quickly",
                    "ua": "szybki → szybko"
                },
                {
                    "en": "careful → carefully",
                    "ua": "ostrożny → ostrożnie"
                },
                {
                    "en": "slow → slowly",
                    "ua": "wolny → wolno"
                }
            ]
        },
        {
            "label": "Końcówka -y → -ily",
            "color": "blue",
            "description": "Jeśli przymiotnik kończy się na <strong>-y</strong>, zmieniamy końcówkę na <strong>-ily</strong>:",
            "examples": [
                {
                    "en": "happy → happily",
                    "ua": "szczęśliwy → szczęśliwie"
                },
                {
                    "en": "easy → easily",
                    "ua": "łatwy → łatwo"
                },
                {
                    "en": "angry → angrily",
                    "ua": "zły → gniewnie"
                }
            ]
        },
        {
            "label": "Końcówka -le → -ly",
            "color": "sky",
            "description": "Jeśli przymiotnik kończy się na <strong>-le</strong>, zwykle zamieniamy <strong>-le</strong> na <strong>-ly</strong>:",
            "examples": [
                {
                    "en": "simple → simply",
                    "ua": "prosty → po prostu"
                },
                {
                    "en": "gentle → gently",
                    "ua": "łagodny → łagodnie"
                },
                {
                    "en": "terrible → terribly",
                    "ua": "straszny → strasznie"
                }
            ]
        }
    ]
}

{
    "title": "3. Słowa o tej samej formie",
    "sections": [
        {
            "label": "Fast, hard, late, early",
            "color": "emerald",
            "description": "Niektóre słowa mają <strong>taką samą formę</strong> jako przymiotnik i jako przysłówek:",
            "examples": [
                {
                    "en": "a fast car / He drives fast.",
                    "ua": "szybki samochód / On jeździ szybko."
                },
                {
                    "en": "hard work / She works hard.",
                    "ua": "ciężka praca / Ona ciężko pracuje."
                },
                {
                    "en": "an early morning / I woke up early.",
                    "ua": "wczesny poranek / Obudziłem się wcześnie."
                }
            ]
        },
        {
            "label": "Uwaga: hardly ≠ hard",
            "color": "rose",
            "description": "<strong>Hardly</strong> znaczy „ledwo, prawie wcale”, a nie „ciężko”:",
            "examples": [
                {
                    "en": "I can hardly see anything.",
                    "ua": "Ledwo cokolwiek widzę."
                },
                {
                    "en": "She hardly ever calls me.",
                    "ua": "Ona prawie nigdy do mnie nie dzwoni."
                }
            ]
        },
        {
            "label": "Uwaga: lately ≠ late",
            "color": "amber",
            "description": "<strong>Lately</strong> znaczy „ostatnio”, a nie „późno”:",
            "examples": [
                {
                    "en": "I arrived late.",
                    "ua": "Przyjechałem późno."
                },
                {
                    "en": "Lately, I have been busy.",
                    "ua": "Ostatnio byłem zajęty."
                }
            ]
        }
    ]
}

{
    "title": "4. Good vs Well",
    "intro": "Jednym z najczęstszych błędów jest mylenie <strong>good</strong> (przymiotnik) z <strong>well</strong> (przysłówek):",
    "rows": [
        {
            "en": "She is a good singer.",
            "ua": "Ona jest dobrą piosenkarką."
            ,"note": "✓ przymiotnik good opisuje singer"
        },
        {
            "en": "She sings well.",
            "ua": "Ona śpiewa dobrze.",
            "note": "✓ przysłówek well opisuje sings"
        },
        {
            "en": "❌ She sings good.",
            "ua": "BŁĄD!",
            "note": "Poprawnie: She sings well."
        },
        {
            "en": "❌ She is a well singer.",
            "ua": "BŁĄD!",
            "note": "Poprawnie: She is a good singer."
        }
    ],
    "warning": "💡 <strong>Well</strong> jako przymiotnik może też znaczyć „zdrowy”: I feel well today."
}

{
    "title": "5. Pozycja w zdaniu",
    "sections": [
        {
            "label": "Przymiotniki",
            "color": "emerald",
            "description": "Przymiotniki stoją <strong>przed rzeczownikiem</strong> albo <strong>po to be / linking verbs</strong>:",
            "examples": [
                {
                    "en": "an expensive car",
                    "ua": "drogi samochód"
                },
                {
                    "en": "The car is expensive.",
                    "ua": "Samochód jest drogi."
                },
                {
                    "en": "The soup smells delicious.",
                    "ua": "Zupa pachnie pysznie."
                }
            ]
        },
        {
            "label": "Przysłówki",
            "color": "blue",
            "description": "Przysłówki zwykle stoją <strong>po czasowniku</strong> albo <strong>na końcu zdania</strong>:",
            "examples": [
                {
                    "en": "He speaks clearly.",
                    "ua": "On mówi wyraźnie."
                },
                {
                    "en": "She answered the question correctly.",
                    "ua": "Ona odpowiedziała na pytanie poprawnie."
                },
                {
                    "en": "They drive carefully.",
                    "ua": "Oni jeżdżą ostrożnie."
                }
            ]
        },
        {
            "label": "Przysłówki częstotliwości",
            "color": "sky",
            "description": "Przysłówki częstotliwości (always, usually, often) stoją <strong>przed czasownikiem głównym</strong>:",
            "examples": [
                {
                    "en": "I always wake up early.",
                    "ua": "Zawsze budzę się wcześnie."
                },
                {
                    "en": "She never drinks coffee.",
                    "ua": "Ona nigdy nie pije kawy."
                }
            ]
        }
    ]
}

{
    "title": "6. Typowe błędy",
    "sections": [
        {
            "label": "Błąd 1: real / really",
            "color": "rose",
            "description": "<strong>Real</strong> to przymiotnik, a <strong>really</strong> to przysłówek („naprawdę”, „bardzo”):",
            "examples": [
                {
                    "en": "✓ This is a real diamond.",
                    "ua": "To prawdziwy diament."
                },
                {
                    "en": "✓ I really like this song.",
                    "ua": "Naprawdę lubię tę piosenkę."
                },
                {
                    "en": "❌ I real like this. → ✓ I really like this.",
                    "ua": "BŁĄD"
                }
            ]
        },
        {
            "label": "Błąd 2: bad / badly",
            "color": "rose",
            "description": "<strong>Bad</strong> to przymiotnik, a <strong>badly</strong> to przysłówek:",
            "examples": [
                {
                    "en": "✓ I feel bad.",
                    "ua": "Źle się czuję."
                },
                {
                    "en": "✓ He played badly.",
                    "ua": "On grał źle."
                },
                {
                    "en": "❌ He played bad. → ✓ He played badly.",
                    "ua": "BŁĄD"
                }
            ]
        },
        {
            "label": "Błąd 3: po linking verbs",
            "color": "amber",
            "description": "Po <strong>linking verbs</strong> (feel, look, smell, taste, sound) używamy <strong>przymiotnika</strong>:",
            "examples": [
                {
                    "en": "✓ The food tastes good.",
                    "ua": "Jedzenie dobrze smakuje."
                },
                {
                    "en": "✓ You look tired.",
                    "ua": "Wyglądasz na zmęczonego."
                },
                {
                    "en": "✓ This sounds interesting.",
                    "ua": "To brzmi interesująco."
                }
            ]
        }
    ]
}

{
    "title": "7. Zmiana znaczenia z -ly",
    "intro": "Niektóre słowa zmieniają znaczenie, gdy występują jako przysłówek z końcówką -ly:",
    "rows": [
        {
            "en": "hard / hardly",
            "ua": "ciężko / ledwo",
            "note": "He works hard. / He hardly works."
        },
        {
            "en": "late / lately",
            "ua": "późno / ostatnio",
            "note": "I arrived late. / Lately, I am busy."
        },
        {
            "en": "near / nearly",
            "ua": "blisko / prawie",
            "note": "Come near. / I nearly forgot."
        },
        {
            "en": "high / highly",
            "ua": "wysoko / bardzo, wysoko ceniony",
            "note": "Fly high. / Highly recommended."
        },
        {
            "en": "short / shortly",
            "ua": "krótko / wkrótce",
            "note": "Cut it short. / I will call shortly."
        }
    ],
    "warning": "💡 Zawsze sprawdzaj w słowniku znaczenie formy z -ly — może ono różnić się od podstawowego przymiotnika."
}

{
    "title": "8. Praktyczne wskazówki",
    "intro": "Jak ustalić, czy potrzebujesz przymiotnika, czy przysłówka:",
    "items": [
        {
            "label": "Krok 1",
            "title": "Sprawdź, co opisujesz",
            "subtitle": "Rzeczownik → przymiotnik. Czasownik → przysłówek."
        },
        {
            "label": "Krok 2",
            "title": "Zadaj pytanie",
            "subtitle": "Jaki? Jaka? → przymiotnik. Jak? → przysłówek."
        },
        {
            "label": "Krok 3",
            "title": "Sprawdź formę",
            "subtitle": "Większość przysłówków kończy się na -ly."
        },
        {
            "label": "Krok 4",
            "title": "Pamiętaj o wyjątkach",
            "subtitle": "fast, hard, early, late mają tę samą formę."
        }
    ]
}

{
    "title": "9. Dodatkowe przypadki",
    "sections": [
        {
            "label": "Przysłówki opisujące przymiotniki",
            "color": "emerald",
            "description": "Przysłówki mogą opisywać <strong>przymiotniki</strong>, wzmacniając je albo osłabiając:",
            "examples": [
                {
                    "en": "It is extremely hot today.",
                    "ua": "Dziś jest wyjątkowo gorąco."
                },
                {
                    "en": "She is very beautiful.",
                    "ua": "Ona jest bardzo piękna."
                },
                {
                    "en": "This is quite interesting.",
                    "ua": "To jest całkiem interesujące."
                }
            ]
        },
        {
            "label": "Inne przysłówki",
            "color": "blue",
            "description": "Przysłówki mogą też opisywać inne <strong>przysłówki</strong>:",
            "examples": [
                {
                    "en": "He drives very carefully.",
                    "ua": "On jeździ bardzo ostrożnie."
                },
                {
                    "en": "She speaks extremely quickly.",
                    "ua": "Ona mówi niezwykle szybko."
                },
                {
                    "en": "They work surprisingly well together.",
                    "ua": "Oni zaskakująco dobrze ze sobą współpracują."
                }
            ]
        }
    ]
}
